  ('real-estate-moex-00320', 'real-estate', 'real-estate-moex-112-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '就法定夫妻財產制之敘述，下列何者錯誤？', '["夫或妻婚前財產，於婚姻關係存續中所生之孳息，視為婚後財產", "不能證明為夫或妻所有之財產，視為夫妻共有", "夫或妻之財產分為婚前財產與婚後財產，由夫妻各自所有", "夫妻各自對其債務負清償之責"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:34+00:00", "source_pdf_sha1": "8603d51632e6", "answer_pdf_sha1": "a355fa6017e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00321', 'real-estate', 'real-estate-moex-112-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於民法第1031條之1夫妻財產制中之特有財產之敘述，下列何者錯誤？', '["甲在婚前取得之受贈物A屋，若贈與人甲父以書面聲明甲日後結婚時，該A屋為特有財產，則 該A屋亦屬特有財產", "夫或妻在家中共同使用的茶杯、桌椅等動產，非特有財產", "夫是音樂家，則其演奏時所需之樂器為特有財產", "夫或妻雖以受贈之特有財產之金錢購買不動產一筆，惟該受贈物狀態已變更，則該不動產非特 有財產"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:34+00:00", "source_pdf_sha1": "8603d51632e6", "answer_pdf_sha1": "a355fa6017e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00322', 'real-estate', 'real-estate-moex-112-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於遺產繼承之敘述，下列何者錯誤？', '["非婚生子女非經生父認領或準正，不得繼承其生父之遺產", "遺產繼承人，除配偶外，其繼承順序為直系血親卑親屬、父母、兄弟姊妹、祖父母", "配偶與被繼承人直系血親尊親屬同為繼承時，其應繼分為遺產之三分之一", "特留分之規定，係為保障法定繼承人之權利免受侵害"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:34+00:00", "source_pdf_sha1": "8603d51632e6", "answer_pdf_sha1": "a355fa6017e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00323', 'real-estate', 'real-estate-moex-112-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於回復喪失繼承權之敘述，下列何者錯誤？', '["子女為了遺產而謀殺父親，即喪失對父親之繼承權，因被繼承人原諒繼承人之行為而回復繼承權", "偽造、變造、隱匿、湮滅被繼承人關於繼承之遺囑者，喪失繼承權，得因被繼承人原諒繼承人 之行為而回復其繼承權", "對於被繼承人有重大之虐待或侮辱情事，經被繼承人表示其不得繼承時，喪失繼承權，但之後 仍可因獲得被繼承人之原諒而回復繼承權", "以詐欺或脅迫妨害被繼承人為關於繼承之遺囑，或妨害其撤回或變更者，喪失繼承權，得因被 繼承人原諒繼承人之行為而回復其繼承權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:34+00:00", "source_pdf_sha1": "8603d51632e6", "answer_pdf_sha1": "a355fa6017e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
