  ('real-estate-moex-00332', 'real-estate', 'real-estate-moex-111-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '利用計量模型分析法進行估價，應蒐集相當數量具代表性之比較標的，在計量模型的影響不動產 價格之因素中，現有6項區域因素，5項個別因素，因此至少要蒐集多少數量以上之比較標的才 符合不動產估價技術規則之規定？', '["55筆以上", "40筆以上", "30筆以上", "25筆以上"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:34+00:00", "source_pdf_sha1": "b8ef2ad8a84f", "answer_pdf_sha1": "874ce765e0f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
